// รับข้อมูลจาก webhook
const body = $('Webhook: Analyze').first()?.json?.body || {};
const session  = body.session  || '';
const teamName = body.teamName || session;
const apiKey   = body.apiKey   || '';
const customRubric = body.rubric || '';

if (!session) throw new Error('session is required');
if (!apiKey)  throw new Error('apiKey is required');

// กรองข้อมูลตาม session
const rows = $input.all().map(r => r.json);
const filtered = rows.filter(r => r['Session ID'] === session);

if (filtered.length === 0) throw new Error('No data found for session: ' + session);

// เอาเฉพาะ STT (คำพูดผู้นำเสนอ)
const sttRows = filtered.filter(r => r['Type'] === 'stt');
if (sttRows.length === 0) throw new Error('No speech data (stt) found for session: ' + session);

// สร้าง transcript
const conversationText = sttRows
  .map((r, i) => `[${i + 1}] ${r['Text']}`)
  .join('\n');

// เกณฑ์การให้คะแนน
const rubric = customRubric || `1. ความคิดสร้างสรรค์ (Creativity) — 0-25 คะแนน: ความแปลกใหม่และความสร้างสรรค์ของไอเดีย
2. ความเป็นไปได้ (Feasibility) — 0-25 คะแนน: สามารถนำไปทำจริงได้มากน้อยแค่ไหน
3. ความชัดเจนในการนำเสนอ (Clarity) — 0-25 คะแนน: นำเสนอได้เข้าใจง่าย มีโครงสร้างชัดเจน
4. ผลกระทบที่คาดหวัง (Impact) — 0-25 คะแนน: ประโยชน์และผลกระทบต่อสังคมหรือธุรกิจ`;

// สร้าง prompt
const prompt = `คุณเป็น AI ผู้ตัดสินการแข่งขันไอเดีย กรุณาวิเคราะห์และให้คะแนนการนำเสนอต่อไปนี้อย่างเป็นกลาง

ทีม: ${teamName}
จำนวนข้อความที่พูด: ${sttRows.length} ข้อความ

--- บทสนทนา / การนำเสนอ ---
${conversationText}
--- สิ้นสุดบทสนทนา ---

เกณฑ์การให้คะแนน:
${rubric}

กรุณาตอบในรูปแบบ JSON เท่านั้น ไม่มีข้อความอื่นนอก JSON:
{
  "totalScore": <รวม 0-100>,
  "breakdown": {
    "creativity": <0-25>,
    "feasibility": <0-25>,
    "clarity": <0-25>,
    "impact": <0-25>
  },
  "summary": "สรุปผลการนำเสนอภาษาไทย 2-3 ประโยค",
  "strengths": ["จุดเด่น 1", "จุดเด่น 2"],
  "improvements": ["ข้อควรปรับปรุง 1", "ข้อควรปรับปรุง 2"]
}`;

return [{
  json: { session, teamName, apiKey, prompt, sttCount: sttRows.length }
}];

// ดึงผลจาก Gemini
const geminiResponse = $input.first().json;
const textContent = geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

let result;
try {
  result = JSON.parse(textContent);
} catch (e) {
  // ลอง extract JSON จาก text กรณีมี markdown wrapper
  const match = textContent.match(/\{[\s\S]*\}/);
  result = match ? JSON.parse(match[0]) : { error: 'Parse failed', raw: textContent };
}

// ดึง context จาก Build Prompt node
const ctx = $('Build Prompt').first().json;
const now = new Date().toISOString();

const totalScore  = result.totalScore || 0;
const creativity  = result.breakdown?.creativity  || 0;
const feasibility = result.breakdown?.feasibility || 0;
const clarity     = result.breakdown?.clarity     || 0;
const impact      = result.breakdown?.impact      || 0;

return [{
  json: {
    session:      ctx.session,
    teamName:     ctx.teamName,
    totalScore,
    creativity,
    feasibility,
    clarity,
    impact,
    summary:      result.summary      || '',
    strengths:    JSON.stringify(result.strengths    || []),
    improvements: JSON.stringify(result.improvements || []),
    analyzedAt:   now,
    sttCount:     ctx.sttCount
  }
}];

const d = $('Parse Result').first().json;
return [{
  json: {
    ok: true,
    session:   d.session,
    teamName:  d.teamName,
    totalScore: d.totalScore,
    breakdown: {
      creativity:  d.creativity,
      feasibility: d.feasibility,
      clarity:     d.clarity,
      impact:      d.impact
    },
    summary:      d.summary,
    strengths:    JSON.parse(d.strengths    || '[]'),
    improvements: JSON.parse(d.improvements || '[]'),
    sttCount:     d.sttCount,
    analyzedAt:   d.analyzedAt
  }
}];
